mapper.select:
/* 토론 참여 목록 조회 ForumJoinUserDAO.listStdScore */ SELECT ROW_NUMBER() OVER() AS lineNo , stdNo , SCR , CASE WHEN atclCnt > 0 OR cmntCnt > 0 THEN '참여' ELSE '미참여' eND AS joinStatus , atclCnt , cmntCnt , teamCd FROM ( SELECT A.USER_ID AS stdNo , NVL(C.SCR, 0) AS SCR , (SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL AS B WHERE B.DSCS_ID = #{forumCd} AND B.USER_ID = A.USER_ID AND B.DELYN = 'N' ) as atclCnt , (SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT AS B WHERE B.DSCS_ID = #{forumCd} AND B.USER_ID = A.USER_ID AND B.DELYN = 'N') as cmntCnt , C.TEAM_ID AS teamCd FROM TB_LMS_ATNDLC AS A LEFT JOIN TB_LMS_DSCS_PTCP AS C ON A.USER_ID = C.USER_ID AND C.DSCS_ID = #{forumCd} WHERE A.SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S' )T WHERE 1 = 1
AND stdNo IN
#{item}
AND ( atclCnt > 0 or cmntCnt > 0 )
AND ( atclCnt = 0 and cmntCnt = 0 )
AND stdNo = #{stdNo}

mapper.update:
/*
	교수 메모 수정
	ForumJoinUserDAO.editForumProfMemo
*/
UPDATE TB_LMS_DSCS_PTCP SET
	MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()
	, SCR_MEMO = #{profMemo}
WHERE DSCS_ID = #{forumCd}
	AND USER_ID = #{stdNo}

mapper.select:
/*
	토론 참여자 테이블에 해당 참여자가 있는지 체크
	ForumJoinUserDAO.getForumJoinUser
*/
SELECT
	COUNT(*)
FROM TB_LMS_DSCS_PTCP
WHERE USER_ID = #{stdNo}
	AND DSCS_ID = #{forumCd}

/*
	메모
	ForumJoinUserDAO.getMemo
*/
SELECT
	SCR_MEMO as profMemo
FROM TB_LMS_DSCS_PTCP
WHERE USER_ID = #{stdNo}
	AND DSCS_ID = #{forumCd}

/* 넘겨 받은 글자수에 해당하는 토론 참여자 조회 ForumJoinUserDAO.getSelectCtsLen */ SELECT COUNT(*) FROM TB_LMS_DSCS_PTCP A LEFT JOIN TB_LMS_DSCS_ATCL B ON (A.DSCS_ID = B.DSCS_ID AND A.USER_ID = B.USER_ID AND B.DELYN = 'N')
LEFT JOIN TB_LMS_DSCS_CMNT C ON (A.DSCS_ID = C.DSCS_ID AND A.USER_ID = C.USER_ID AND C.DELYN = 'N')
WHERE A.DSCS_ID = #{forumCd} AND A.USER_ID = #{stdNo} AND B.ATCL_CTS_LEN >= #{ctsLen}
AND (B.ATCL_CTS_LEN >= #{ctsLen} OR C.CMNT_CTS_LEN >= #{ctsLen})

mapper.insert:
/*
	참여자가 없을 때 토론 참여자 테이블 삽입
	ForumJoinUserDAO.chkStdNoInsert
*/
INSERT INTO TB_LMS_DSCS_PTCP (
	USER_ID
	, DSCS_ID
	, RGTR_ID
	, FRST_INQ_DTTM
)
SELECT
	#{stdNo}
	, #{forumCd}
	, 'ADMIN'
	, FN_DTTM()
FROM TB_LMS_DSCS_PTCP
WHERE NOT EXISTS (
	SELECT
		USER_ID
	FROM TB_LMS_DSCS_PTCP
	WHERE USER_ID = #{stdNo}
		AND DSCS_ID = #{forumCd}
) ROWNUM = 1

/* 모든 참여자를 토론 참여자 테이블에 삽입 ForumJoinUserDAO.insertJoinUser */ INSERT INTO TB_LMS_DSCS_PTCP ( USER_ID , DSCS_ID , TEAM_ID
, SCR , EVLYN
, RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM ) SELECT A.USER_ID , B.DSCS_ID , ( SELECT E.TEAM_ID FROM TB_LMS_TEAM_CTGR C LEFT JOIN TB_LMS_TEAM D ON C.TEAM_TYCD = D.TEAM_TYCD LEFT JOIN TB_LMS_TEAM_MBR E ON D.TEAM_ID = E.TEAM_ID WHERE 1 = 1 AND C.TEAM_TYCD = B.TEAM_TYCD AND E.USER_ID = A.USER_ID ) AS teamCd
, 100 , 'Y'
, #{rgtrId} , FN_DTTM() , #{rgtrId} , FN_DTTM() FROM TB_LMS_ATNDLC A LEFT JOIN TB_LMS_DSCS B ON A.SBJCT_ID = B.SBJCT_ID WHERE A.SBJCT_ID = #{crsCreCd} AND A.ATNDLC_STSCD = 'S' AND B.DELYN = 'N' AND B.DSCS_ID = #{forumCd}
AND A.USER_ID = #{stdNo}
ON DUPLICATE KEY UPDATE USER_ID = A.USER_ID , DSCS_ID = B.DSCS_ID
, SCR = 100 , EVLYN = 'Y'

/* 참여형 일괄평가 ForumJoinUserDAO.participateScore */ INSERT INTO TB_LMS_DSCS_PTCP ( USER_ID , DSCS_ID , TEAM_ID , SCR , EVLYN , RGTR_ID , FRST_INQ_DTTM , MDFR_ID , MOD_DTTM ) ( SELECT T.USER_ID , T.DSCS_ID , T.TEAM_ID , T.SCR , 'Y' , #{rgtrId} , FN_DTTM() , #{rgtrId} , FN_DTTM() FROM ( SELECT * , (SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.DSCS_ID AND DELYN = 'N' AND USER_ID = A.USER_ID) AS atclCnt , (SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = A.DSCS_ID AND DELYN = 'N' AND USER_ID = A.USER_ID) AS cmntCnt FROM TB_LMS_DSCS_PTCP A WHERE A.DSCS_ID = #{forumCd}
AND A.EVLYN = 'N'
) T WHERE 1 = 1
AND T.atclCnt = 0
AND T.atclCnt > 0
) ON DUPLICATE KEY UPDATE USER_ID = T.USER_ID , DSCS_ID = T.DSCS_ID , EVLYN = 'Y'
, SCR = 0
, SCR = 100

mapper.update:
/*
	학습자 팀 수정
	ForumJoinUserDAO.updateStdTeam
*/
UPDATE TB_LMS_DSCS_PTCP SET
	TEAM_ID = #{teamCd}
 WHERE DSCS_ID = #{forumCd}
   AND USER_ID = #{stdNo}

/*
	평가여부 초기화
	ForumJoinUserDAO.updateJoinUserEvalN
*/
UPDATE TB_LMS_DSCS_PTCP SET
	  EVLYN = 'N'
	, SCR = NULL
	, MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()
 WHERE DSCS_ID = #{forumCd}
   AND USER_ID = #{stdNo}
